        unordered_map<string, int> freq;
        for (string& word : words) {
            freq[word]++;
        }
        vector<pair<string, int>> wordFreq(freq.begin(), freq.end());
        sort(wordFreq.begin(), wordFreq.end(), [](const auto& a, const auto& b) {
            if (a.second == b.second) {
